    CFBundleTypeExtensions

      {{.Ext}}

    CFBundleTypeName
    {{.Name}}
    CFBundleTypeRole
    {{.Role}}
    CFBundleTypeIconFile
    {{.IconName}}

  {{end}}

{{end}}
{{if .Info.Protocols}}
CFBundleURLTypes

  {{range .Info.Protocols}}

        CFBundleURLName
        com.wails.{{.Scheme}}
        CFBundleURLSchemes

            {{.Scheme}}

        CFBundleTypeRole
        {{.Role}}

  {{end}}

{{end}}
